var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야? 그거?","JPN":" それ何？","ENG":"Huh? What's that?","TWN":"那是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"바나나? 내 생각이 나서 오는 길에 샀다고?","JPN":" バナナ？　あたしのことを思い出して帰りに買ってきたの？","ENG":"A banana? You bought it while thinking of me?","TWN":"香蕉？你說來的路上想到我，所以特地買的？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"특별한 볼일이 있대서 와줬더니, 겨우 그런 걸로 부른 거야?","JPN":" 特別な用があるっていうから来てあげたら、そんなことで呼んだの？","ENG":"I thought you had something important to say, but you called me in here just for this?","TWN":"我還以為你找我來是有什麼特別的事，結果只是要給我香蕉？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐… 마음에 들었으니까 맛있게 먹어는 줄게.","JPN":" まあ……気に入ったから食べてあげる。","ENG":"Well... I like it, so I'll enjoy the banana.","TWN":"好吧…。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"응? 바나나 때문에 부른 거 아니라고?","JPN":" え？　バナナのことで呼んだんじゃないの？","ENG":"Hmm? You didn't want to see me because of the banana?","TWN":"嗯？找我來的重點不是香蕉？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"종신계약? 그게 뭔데?","JPN":" 終身契約？　それ何？","ENG":"A lifetime contract? What's that?","TWN":"終身契約？那是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"가만… 종신이라면 설마?","JPN":" ちょっと待って……終身ってまさか？","ENG":"Wait... a lifetime contract means...","TWN":"等等…終身？難道是？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너 말이야. 우리가 이방인이라고 수상한 계약으로 이용해먹을 생각은 아니겠지?!","JPN":" あなたね。あたしたちが異邦人だからって怪しい契約をさせてこき使うつもりなんじゃない！？","ENG":"Hey. You're not trying to take advantage of us outsiders with a fishy contract, are you?!","TWN":"我說你，該不會因為我們是外邦人，你就想用奇怪的契約來利用我們？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아, 아냐?","JPN":" え、違う？","ENG":"Th-that's not it?","TWN":"喔，不是喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아니면 말지 그렇게 노려볼 건 없잖아. 아무리 친한 사이라도 계약은 신중해야하는 법이라고.","JPN":" 違うなら悪いけど、そんなに睨むことないじゃない。いくら親しい仲でも契約は慎重にするものでしょ。","ENG":"You could've just said that without glaring at me. Even if we're close, contracts have to be made carefully.","TWN":"不是就不是，幹嘛那樣盯著人家看。就算是很熟的關係，契約這種東西還是謹慎點好。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"아, 알겠어. 내용만 읽고 사인할게! 됐지?","JPN":" わ、わかった。内容だけ読んでサインするね！　それでいいでしょ？","ENG":"Fine. Let me read it first, then I'll sign it! Happy?","TWN":"好…好啦！我看個內容就簽名！這樣總可以吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"역시 엄청 수상한 내용 맞잖아! 나한테만 일방적으로 신용을 요구하는 계약이라니 불공평해!","JPN":" やっぱりすごく怪しいじゃない！　あたしにだけ一方的に信用を要求する契約なんて不公平よ！","ENG":"This is fishy as heck! It's unfair how this contract asks for my trust but not yours!","TWN":"我就知道，內容超奇怪的！根本是單方面要求我講信用，不公平！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥, 내 사인을 원한다면 너도 내 계약서에 사인해야 할 거야.","JPN":" ふん、あたしのサインが欲しいなら、あなたもあたしの契約書にサインしなくちゃね。","ENG":"Hmph! If you want me to sign that, you'll have to sign my contract first.","TWN":"哼，要是想要我簽名，那你也必須在我的契約書上簽名才行。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"복종 노예? 뭐, 뭐라는 거야! 내 계약서엔 그런 이상한 내용 없거든?!","JPN":" 服従奴隷？　な、何言ってるのよ！　あたしの契約書にはそんな変な内容はないんだから！","ENG":"\\"Obedient slave?\\" W-what are you talking about?! It doesn't say anything about that!","TWN":"當我的奴隸？胡…胡說什麼你！我的契約書上才沒有這種不三不四的內容！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그냥… 나랑 지낼 거면 내 곁에 자주 있어야 한다는 내용인데…","JPN":" ただ……あたしと過ごすならあたしのそばにいつもいなくちゃいけないっていう内容なんだけど……","ENG":"It just says... that you have to stay by my side often if you're going to be with me...","TWN":"我的要求只有…之後若是我們要一起共事，那你必須常常陪在我身邊…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"잠깐, 역시 항목을 더 추가하는 게 좋겠어. 매일 포도 두 송이, 아니 세 송이씩…!","JPN":" ちょっと待って、やっぱり項目をもっと追加した方がいいわ。毎日ブドウ2房、いや3房ずつ……！","ENG":"Wait! I think there's another thing I should add. You have to give me two, no three clusters of grapes every day...!","TWN":"等等，我要再多加一條！每天提供二串葡萄，不對，還是三串…！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"엑? 사인 끝났다고? 벌써?","JPN":" えっ？　サインしたの？　もう？","ENG":"Huh? You already signed it?","TWN":"什麼？你已經簽好啦？這麼快？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};